import './App.css';
import SearchBar from './components/SearchBar';
import ErrorMessage from './components/ErrorMessage';
import WeatherCard from './components/WeatherCard';
import Loader from './components/Loader';
import { useEffect, useState } from 'react';
import axios from 'axios';

const App = () => {
  const [city, setCity] = useState('');
  const [tcity, setTcity] = useState('');
  const [icon, setIcon] = useState('');
  const [temperature, setTemperature] = useState('');
  const [wind, setWind] = useState('');
  const [humidity, setHumidity] = useState('');
  const [tempValue, setTempValue] = useState(null);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const API_KEY = "695edf5a6a0814d2cb6d7c8f0f21e545";

  //  Fetch Weather Function
  const fetchWeather = async (cityName) => {
    try {
      setLoading(true);
      setError('');

      const { data } = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${cityName}&appid=${API_KEY}&units=metric`
      );

      // ✅ Destructuring
      const {
        name,
        main: { temp, humidity },
        wind: { speed },
        weather,
      } = data;

      setTcity(name);
      setTemperature(`Temperature: ${temp}°C`);
      setWind(`Wind Speed: ${speed} m/s`);
      setHumidity(`Humidity: ${humidity}%`);
      setIcon(`https://openweathermap.org/img/wn/${weather[0].icon}@2x.png`);
      setTempValue(temp);

    } catch (err) {
      setError('City not found');
    } finally {
      setLoading(false);
    }
  };

  // Load default city
  useEffect(() => {
    fetchWeather("Visakhapatnam");
  }, []);

  //  Button handler
  const checkWeather = () => {
    if (!city) {
      setError("Enter city name");
      return;
    }
    fetchWeather(city);
    setCity('');
  };

  return (
    <div className="screen">
      <div className='main'>
        <h1>Weather App</h1>

        <SearchBar 
           city={city} 
           setCity={setCity} 
           onSearch={checkWeather} 
        />

        {loading && <Loader />}
        {error && <ErrorMessage message={error} />}

        {tcity && !loading && (
          <WeatherCard
            city={tcity}
            icon={icon}
            temperature={temperature}
            wind={wind}
            humidity={humidity}
          />
        )}
      </div>
    </div>
  );
};

export default App;
